module add1 (
    input a,
    input b,
    input Cin,
    output y,
    output Co
);
    assign y = ((~a) & (~b) & Cin | (~a) & b & (~Cin) | a & (~b) & (~Cin) | (a & b & Cin));
    assign Co = ((~a & b & Cin) | (a & ~b & Cin) | (a & b & ~Cin) | (a & b & Cin));

endmodule

module edge_detect (
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

reg a_sync;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        a_sync <= 1'b0;
    end else begin
        a_sync <= a;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        rise <= 1'b0;
        down <= 1'b0;
    end else begin
        if (a_sync == 1'b0 && a == 1'b1) begin
            rise <= 1'b1;
            down <= 1'b0;
        end else if (a_sync == 1'b1 && a == 1'b0) begin
            rise <= 1'b0;
            down <= 1'b1;
        end else begin
            rise <= 1'b0;
            down <= 1'b0;
        end
    end
end

endmodule

