module cla_4bit(
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout,
    output p_group,
    output g_group
);
    wire [3:0] p; 
    wire [3:0] g; 
    wire [4:0] c; 


    assign p = a ^ b;
    assign g = a & b;


    assign c[0] = cin;
    assign c[1] = g[0] | (p[0] & c[0]);
    assign c[2] = g[1] | (p[1] & c[1]);
    assign c[3] = g[2] | (p[2] & c[2]);
    assign c[4] = g[3] | (p[3] & c[3]);


    assign sum = p ^ {c[3:0]};


    assign p_group = p[0] & p[1] & p[2] & p[3];
    assign g_group = g[3] | (g[2] & p[3]) | (g[1] & p[3] & p[2]) | (g[0] & p[3] & p[2] & p[1]);


    assign cout = c[4];
endmodule

module signal_generator (
    input clk,
    input rst_n,
    output reg [4:0] wave
);

localparam UP_STATE = 2'b00;
localparam DOWN_STATE = 2'b01;

reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= UP_STATE;
        wave <= 5'b0;
    end
    else begin
        case (state)
            UP_STATE: begin
                if (wave == 5'b11111) begin
                    state <= DOWN_STATE;
                end
                else begin
                    wave <= wave + 1;
                end
            end
            DOWN_STATE: begin
                if (wave == 5'b00000) begin
                    state <= UP_STATE;
                end
                else begin
                    wave <= wave - 1;
                end
            end
        endcase
    end
end

endmodule

module fsm #(
    parameter s0 = 3'b000,
    parameter s1 = 3'b001,
    parameter s2 = 3'b010,
    parameter s3 = 3'b011,
    parameter s4 = 3'b100,
    parameter s5 = 3'b101
) (
    input IN,
    output reg MATCH,
    input CLK,
    input RST
);

parameter S0 = 3'b000;
parameter S1 = 3'b001;
parameter S2 = 3'b010;
parameter S3 = 3'b011;
parameter S4 = 3'b100;
parameter S5 = 3'b101;

reg [2:0] current_state, next_state;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        current_state <= S0;
    end else begin
        current_state <= next_state;
    end
end

always @(*) begin
    case(current_state)
        S0: begin
            if(IN == 1'b1) begin
                next_state = S1;
                MATCH = 1'b0;
            end else begin
                next_state = S0;
                MATCH = 1'b0;
            end
        end
        S1: begin
            if(IN == 1'b0) begin
                next_state = S2;
                MATCH = 1'b0;
            end else begin
                next_state = S1;
                MATCH = 1'b0;
            end
        end
        S2: begin
            if(IN == 1'b0) begin
                next_state = S3;
                MATCH = 1'b0;
            end else begin
                next_state = S1;
                MATCH = 1'b0;
            end
        end
        S3: begin
            if(IN == 1'b1) begin
                next_state = S4;
                MATCH = 1'b0;
            end else begin
                next_state = S0;
                MATCH = 1'b0;
            end
        end
        S4: begin
            if(IN == 1'b1) begin
                next_state = S5;
                MATCH = 1'b1;
            end else begin
                next_state = S0;
                MATCH = 1'b0;
            end
        end
        S5: begin
            if(IN == 1'b0) begin
                next_state = S2;
                MATCH = 1'b0;
            end else begin
                next_state = S1;
                MATCH = 1'b0;
            end
        end
        default: begin
            next_state = S0;
            MATCH = 1'b0;
        end
    endcase
end
endmodule

