module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);


wire [7:0] mul_a_ext, mul_b_ext;
wire [7:0] partial_product[3:0];
reg [7:0] sum_tmp1, sum_tmp2;
reg [7:0] mul_out_reg;

assign mul_a_ext = {{size{1'b0}}, mul_a};
assign mul_b_ext = {{size{1'b0}}, mul_b};

generate
    genvar i;
    for(i = 0; i < size; i = i + 1) begin : gen_partial_products
        assign partial_product[i] = (mul_b_ext[i]) ? (mul_a_ext << i) : 'd0;
    end
endgenerate

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        sum_tmp1 <= 8'd0;
        sum_tmp2 <= 8'd0;
    end else begin
        sum_tmp1 <= (mul_b_ext[0] ? mul_a_ext : 8'd0) + (mul_b_ext[1] ? mul_a_ext << 1 : 8'd0);
        sum_tmp2 <= (mul_b_ext[2] ? mul_a_ext << 2 : 8'd0) + (mul_b_ext[3] ? mul_a_ext << 3 : 8'd0);
    end
end

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_out_reg <= 8'd0;
    end else begin
        mul_out_reg <= sum_tmp1 + sum_tmp2;
    end
end

assign mul_out = mul_out_reg;
endmodule

module right_shifter (
    input clk,
    output reg [7:0] q,
    input d
);
    initial begin
        q = 8'b0;
    end

    always @(posedge clk) begin
        q <= (q >> 1);
        q[7] <= d;
    end
endmodule

module accu (
    input               clk,
    input               rst_n,
    input       [7:0]   data_in,
    input               valid_in,
    output  reg         valid_out,
    output  reg [9:0]   data_out
);

reg [9:0] accum;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        accum <= 0;
        valid_out <= 0;
    end else if (valid_in) begin
        accum <= accum + {1'b0, data_in};
        if (accum == {1'b0, data_in} * 4) valid_out <= 1; else valid_out <= 0;
    end
end

always @(*) begin
    data_out = accum;
end

endmodule

module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output wire valid_out,
    output wire dout
);

reg [3:0] data;
reg valid;
reg [1:0] cnt;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data <= 4'b0;
        valid <= 1'b0;
        cnt <= 2'b0;
    end
    else begin
        if (cnt == 2'd3) begin
            data <= d;
            valid <= 1'b1;
            cnt <= 2'b0;
        end
        else begin
            data <= {data[2:0], data[3]};
            valid <= 1'b0;
            cnt <= cnt + 1;
        end
    end
end

assign dout = data[3];
assign valid_out = valid;

endmodule

