module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

parameter IDLE = 2'b00;
parameter LOAD = 2'b01;
parameter CALCULATE = 2'b10;
parameter OUTPUT = 2'b11;

reg [7:0] mul_a_reg;
reg [7:0] mul_b_reg;

reg [15:0] temp[0:7];

reg [15:0] sum[0:3];

reg [15:0] mul_out_reg;

reg [3:0] mul_en_out_reg;

reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
        mul_en_out_reg <= 4'd0;
        mul_a_reg <= 8'd0;
        mul_b_reg <= 8'd0;
        temp[0] <= 16'd0;
        temp[1] <= 16'd0;
        temp[2] <= 16'd0;
        temp[3] <= 16'd0;
        temp[4] <= 16'd0;
        temp[5] <= 16'd0;
        temp[6] <= 16'd0;
        temp[7] <= 16'd0;
        sum[0] <= 16'd0;
        sum[1] <= 16'd0;
        sum[2] <= 16'd0;
        sum[3] <= 16'd0;
        mul_out_reg <= 16'd0;
    end else begin
        case(state)
            IDLE: begin
                if(mul_en_in) begin
                    state <= LOAD;
                    mul_en_out_reg <= {mul_en_out_reg[2:0], mul_en_in};
                    mul_a_reg <= mul_a;
                    mul_b_reg <= mul_b;
                end
            end

            LOAD: begin
                state <= CALCULATE;
                temp[0] <= mul_b_reg[0] ? {8'd0, mul_a_reg} : 16'd0;
                temp[1] <= mul_b_reg[1] ? {7'd0, mul_a_reg, 1'd0} : 16'd0;
                temp[2] <= mul_b_reg[2] ? {6'd0, mul_a_reg, 2'd0} : 16'd0;
                temp[3] <= mul_b_reg[3] ? {5'd0, mul_a_reg, 3'd0} : 16'd0;
                temp[4] <= mul_b_reg[4] ? {4'd0, mul_a_reg, 4'd0} : 16'd0;
                temp[5] <= mul_b_reg[5] ? {3'd0, mul_a_reg, 5'd0} : 16'd0;
                temp[6] <= mul_b_reg[6] ? {2'd0, mul_a_reg, 6'd0} : 16'd0;
                temp[7] <= mul_b_reg[7] ? {1'd0, mul_a_reg, 7'd0} : 16'd0;
            end

            CALCULATE: begin
                state <= OUTPUT;
                sum[0] <= temp[0] + temp[1];
                sum[1] <= temp[2] + temp[3];
                sum[2] <= temp[4] + temp[5];
                sum[3] <= temp[6] + temp[7];
            end

            OUTPUT: begin
                state <= IDLE;
                mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3];
            end
        endcase
    end
end

assign mul_en_out = mul_en_out_reg[3];

assign mul_out = mul_en_out ? mul_out_reg : 16'd0;
endmodule

module adder_pipe_64bit #(
    parameter DATA_WIDTH = 64,
    parameter STG_WIDTH = 16
) (
    input clk,
    input rst_n,
    input i_en,
    input [DATA_WIDTH-1:0] adda,
    input [DATA_WIDTH-1:0] addb,
    output [DATA_WIDTH:0] result,
    output reg o_en
);

reg [DATA_WIDTH-1:0] adda_reg, addb_reg;
reg [DATA_WIDTH:0] result_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        adda_reg <= 0;
        addb_reg <= 0;
        result_reg <= 0;
        o_en <= 0;
    end else begin
        if (i_en) begin
            adda_reg <= adda;
            addb_reg <= addb;
            result_reg <= {1'b0, adda} + {1'b0, addb};
            o_en <= 1;
        end else begin
            o_en <= 0;
        end
    end
end

assign result = result_reg;

endmodule

module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
);


    reg [7:0] cnt;
    reg [1:0] state;
    reg p_red, p_yellow, p_green;

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            state <= idle;
            p_red <= 1'b0;
            p_yellow <= 1'b0;
            p_green <= 1'b0;
        end
        else begin
            case(state)
                idle: begin
                    p_red <= 1'b0;
                    p_yellow <= 1'b0;
                    p_green <= 1'b0;
                    state <= s1_red;
                end
                s1_red: begin
                    p_red <= 1'b1;
                    p_yellow <= 1'b0;
                    p_green <= 1'b0;
                    if(cnt == 3) begin
                        state <= s3_green;
                    end
                    else begin
                        state <= s1_red;
                    end
                end
                s2_yellow: begin
                    p_red <= 1'b0;
                    p_yellow <= 1'b1;
                    p_green <= 1'b0;
                    if(cnt == 3) begin
                        state <= s1_red;
                    end
                    else begin
                        state <= s2_yellow;
                    end
                end
                s3_green: begin
                    p_red <= 1'b0;
                    p_yellow <= 1'b0;
                    p_green <= 1'b1;
                    if(cnt == 3) begin
                        state <= s2_yellow;
                    end
                    else begin
                        state <= s3_green;
                    end
                end
            endcase
        end
    end

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            cnt <= 8'd10;
        end
        else begin
            if(pass_request && green && (cnt > 10)) begin
                cnt <= 8'd10;
            end
            else if(!green && p_green) begin
                cnt <= 8'd60;
            end
            else if(!yellow && p_yellow) begin
                cnt <= 8'd5;
            end
            else if(!red && p_red) begin
                cnt <= 8'd10;
            end
            else begin
                cnt <= cnt - 1;
            end
        end
    end

    assign clock = cnt;

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            red <= 1'b0;
            yellow <= 1'b0;
            green <= 1'b0;
        end
        else begin
            red <= p_red;
            yellow <= p_yellow;
            green <= p_green;
        end
    end
endmodule
